--------------------------------------------------------------------------------
-- 10_knowledge_docs.sql
-- Creates and populates KNOWLEDGE_DOCS: unstructured corpus for Cortex Search.
-- Target: SNOWFLAKE_REVENUE_CC.CORE
--------------------------------------------------------------------------------

CREATE OR REPLACE TABLE SNOWFLAKE_REVENUE_CC.CORE.KNOWLEDGE_DOCS (
    DOC_ID      STRING      NOT NULL PRIMARY KEY,
    DOC_TYPE    STRING      NOT NULL,
    TITLE       STRING      NOT NULL,
    REGION      STRING      NOT NULL,
    SEGMENT     STRING      NOT NULL,
    ACCOUNT_NAME STRING     NOT NULL,
    SOURCE_DATE DATE        NOT NULL,
    BODY        TEXT        NOT NULL
);

INSERT INTO SNOWFLAKE_REVENUE_CC.CORE.KNOWLEDGE_DOCS
    (DOC_ID, DOC_TYPE, TITLE, REGION, SEGMENT, ACCOUNT_NAME, SOURCE_DATE, BODY)
VALUES
-- ============================================================================
-- INCIDENT POSTMORTEMS
-- ============================================================================
('DOC-001', 'Incident Postmortem', 'INC-0001 Post-Incident Review: West Region Platform Reliability Degradation', 'West', 'Enterprise', 'Acme Financial Services',
 '2026-06-02',
 'Incident INC-0001 was declared on 2026-05-28 at 14:32 UTC when monitoring detected sustained p99 latency spikes exceeding 4500ms on the West region primary compute cluster. The root cause was traced to a cascading failure in the storage tier triggered by a firmware bug in NVMe controllers affecting rack W-14 through W-19. Duration: 6 hours 47 minutes. During this window, 241 Enterprise accounts in the West region experienced query failures, timeout errors, and data pipeline stalls. SLA breach notifications were issued to all affected accounts whose monthly uptime dropped below the contractual 99.95% threshold. Acme Financial Services, our largest West Enterprise account ($4.2M ARR), reported complete inability to run their end-of-month regulatory reporting suite during the incident window. Remediation included emergency firmware patching, failover to secondary storage pools, and proactive customer outreach. Post-incident analysis shows this single event accounts for 73% of all SLA breaches recorded in the West region for May 2026. Renewal risk scoring models now flag 241 West Enterprise accounts at elevated risk (avg score 83/100) directly attributable to INC-0001 impact.'),

('DOC-002', 'Incident Postmortem', 'INC-0001 Customer Impact Assessment: West Enterprise Cohort', 'West', 'Enterprise', 'Pacific Mutual Insurance',
 '2026-06-04',
 'This document details the customer impact of INC-0001 across the West Enterprise segment. Of 312 total West Enterprise accounts, 241 (77%) experienced measurable service degradation during the 6h47m incident window. Impact severity breakdown: 89 accounts experienced complete service unavailability (Severity 1), 112 accounts experienced partial degradation with >50% query failure rate (Severity 2), and 40 accounts experienced intermittent errors (Severity 3). Pacific Mutual Insurance reported that their real-time claims processing pipeline was offline for the full duration, resulting in a backlog of 14,000 claims requiring manual intervention. SLA credits estimated at $2.1M across all affected accounts. The renewal risk model has been updated: accounts with Severity 1 impact now carry an average renewal risk score of 91, Severity 2 averages 83, and Severity 3 averages 72. Key accounts flagged for immediate executive outreach include Acme Financial Services, Pacific Mutual Insurance, Western Digital Analytics, TechNova Solutions, and Cascade Health Systems.'),

('DOC-003', 'Incident Postmortem', 'INC-0001 Root Cause Analysis and Prevention Plan', 'West', 'Enterprise', 'Western Digital Analytics',
 '2026-06-05',
 'Root Cause: INC-0001 originated from a known firmware defect (CVE-2026-3847) in Vendor X NVMe controllers deployed in racks W-14 through W-19. The defect causes controller lockup under sustained high-IOPS workloads when drive temperature exceeds 72C. Contributing factors: (1) Cooling system maintenance window overlapped with peak workload period, raising ambient rack temperature by 4C. (2) Firmware patch had been staged but not yet deployed due to change-freeze policy during month-end processing. (3) Blast radius was amplified because rack affinity rules placed multiple large Enterprise tenants on adjacent racks. Prevention measures implemented: immediate firmware deployment to all affected controllers, revised change-freeze exemption policy for critical security/reliability patches, rack diversity requirement for accounts >$1M ARR, enhanced thermal monitoring with automated workload migration at 68C threshold. Western Digital Analytics lost 4 hours of ETL processing and has formally requested a reliability roadmap review before their August renewal.'),

('DOC-004', 'Incident Postmortem', 'INC-0001 Timeline and Communications Log', 'West', 'Enterprise', 'TechNova Solutions',
 '2026-06-03',
 'INC-0001 Detailed Timeline: 14:32 UTC - Automated alert fires for p99 latency >4000ms on West compute cluster. 14:38 - On-call SRE acknowledges, begins investigation. 14:52 - Severity escalated to SEV-1 after confirming widespread query failures across multiple tenants. 15:05 - Customer-facing status page updated. 15:15 - First batch of SLA breach notifications sent to 89 accounts with complete unavailability. 15:45 - Root cause identified as NVMe controller lockup on racks W-14 to W-19. 16:20 - Emergency failover initiated to secondary storage pools. 18:30 - Partial service restoration for Severity 2 and 3 accounts. 20:45 - Full service restoration confirmed. 21:19 - Incident formally closed. TechNova Solutions ($2.8M ARR) contacted their account executive during the incident to express serious concern about platform reliability ahead of their Q3 renewal decision. Their CTO stated they are evaluating alternative providers if another incident of this magnitude occurs within 90 days.'),

-- ============================================================================
-- SUPPORT CASE NOTES
-- ============================================================================
('DOC-010', 'Support Case Note', 'CASE-88712: Acme Financial Services - Query Timeout Escalation Post INC-0001', 'West', 'Enterprise', 'Acme Financial Services',
 '2026-06-03',
 'Customer: Acme Financial Services. Case opened by VP of Data Engineering. Issue: Following INC-0001, customer reports continued intermittent query timeouts on large aggregation workloads (>500GB scan). Customer states their confidence in platform reliability has been severely impacted. They are requesting: (1) detailed written SLA compliance report for the past 90 days, (2) confirmation of remediation steps taken, (3) meeting with engineering leadership to review reliability roadmap. Customer explicitly mentioned renewal risk, stating "we need to see a credible path to improved reliability before we can commit to a 3-year renewal in August." Current contract: $4.2M ARR, renewal date 2026-08-15. Account health: RED. Renewal risk score: 94/100.'),

('DOC-011', 'Support Case Note', 'CASE-88745: Pacific Mutual Insurance - SLA Credit Request and Performance Concerns', 'West', 'Enterprise', 'Pacific Mutual Insurance',
 '2026-06-04',
 'Customer: Pacific Mutual Insurance. Case opened by CIO office. Issue: Formal SLA credit request for May 2026 downtime during INC-0001. Customer calculates 99.87% uptime for May vs contractual 99.95%, requesting $340K credit. Additionally, customer reports that since INC-0001, they have observed 2-3x longer query compilation times during peak hours (8-10am PT). Engineering investigation shows this is unrelated to INC-0001 (workload growth pattern) but customer perception ties all performance issues to the incident. Customer stated on call: "Every slow query now makes us wonder if another outage is coming. Our board is asking about our cloud vendor concentration risk." Contract: $3.1M ARR, renewal date 2026-09-30. Renewal risk score: 87/100.'),

('DOC-012', 'Support Case Note', 'CASE-88801: TechNova Solutions - Reliability Guarantee Request', 'West', 'Enterprise', 'TechNova Solutions',
 '2026-06-06',
 'Customer: TechNova Solutions. Case opened by CTO directly to account executive. Issue: Customer requesting enhanced SLA terms for renewal - specifically 99.99% uptime guarantee with 10x credit multiplier for breaches, citing INC-0001 as justification. Customer has received competitive proposals from two alternative providers offering 99.99% SLAs with migration support packages. TechNova runs mission-critical fraud detection pipelines that cannot tolerate >5 minutes of downtime. During INC-0001, they experienced 3 hours of complete unavailability resulting in $890K of unprocessed transactions that required manual review. Account executive notes: "This is our most at-risk Enterprise renewal in West. Without a compelling reliability commitment and executive engagement, probability of churn is >60%." Contract: $2.8M ARR, renewal date 2026-07-31. Renewal risk score: 92/100.'),

('DOC-013', 'Support Case Note', 'CASE-88834: Cascade Health Systems - Data Pipeline Recovery Issues', 'West', 'Enterprise', 'Cascade Health Systems',
 '2026-06-07',
 'Customer: Cascade Health Systems. Case opened by Director of Analytics. Issue: While INC-0001 service was restored, customer reports that 3 of their 12 Snowpipe ingestion streams failed to auto-resume after the incident. Manual intervention was required to restart these streams, resulting in an additional 8 hours of data lag beyond the incident window. Customer concerned about data completeness for their CMS regulatory submission due 2026-06-15. Customer requests: (1) root cause for stream non-recovery, (2) assurance that auto-recovery mechanisms will function in future incidents, (3) executive sponsor meeting to discuss overall platform reliability. Contract: $1.9M ARR, renewal 2026-10-15. Renewal risk: 78/100. Note: This account was previously GREEN health; INC-0001 has moved them to YELLOW.'),

('DOC-014', 'Support Case Note', 'CASE-88856: Western Digital Analytics - ETL Failure Compensation', 'West', 'Enterprise', 'Western Digital Analytics',
 '2026-06-08',
 'Customer: Western Digital Analytics. Case opened by Head of Data Platform. Issue: INC-0001 caused complete failure of their nightly ETL pipeline, resulting in 4 hours of data unavailability for downstream BI dashboards used by 2,000+ business users. Customer is requesting SLA credits of $180K plus a formal written commitment that their workloads will be migrated to isolated compute resources before their August renewal. Customer CTO has scheduled a call with our VP Engineering for 2026-06-12 to discuss reliability roadmap. Customer stated: "We selected this platform for reliability. INC-0001 fundamentally challenges that value proposition. We need concrete evidence that this cannot recur before we renew." Contract: $2.4M ARR, renewal 2026-08-31. Renewal risk score: 85/100.'),

('DOC-015', 'Support Case Note', 'CASE-88902: Sierra Manufacturing - Intermittent Connectivity Post-Incident', 'West', 'Enterprise', 'Sierra Manufacturing',
 '2026-06-09',
 'Customer: Sierra Manufacturing. Case opened by IT Director. Issue: Customer reports sporadic connection drops (2-3 per day) since INC-0001. Engineering investigation confirms these are unrelated to the incident (traced to customer-side network configuration change made during their own incident response). However, customer perception remains that platform stability has degraded. Account team notes heightened sensitivity to any performance anomaly. Recommended approach: proactive outreach with detailed telemetry showing current platform stability metrics. Contract: $1.4M ARR, renewal 2026-11-30. Renewal risk score: 71/100. Risk driver: perception of reliability decline post INC-0001, even though current issues are customer-side.'),

('DOC-016', 'Support Case Note', 'CASE-88934: Velocity Logistics - Missed SLA Penalty Clause Triggered', 'West', 'Enterprise', 'Velocity Logistics',
 '2026-06-10',
 'Customer: Velocity Logistics. Case escalated by Legal/Procurement. Issue: Customer contract contains non-standard penalty clause: any month with <99.9% uptime triggers automatic 15% discount on next renewal term. INC-0001 brought May uptime to 99.87%. Customer legal team has formally notified us that the penalty clause is triggered and they expect the discount applied to their October renewal. This represents ~$375K annual revenue reduction on their $2.5M contract. Account team exploring whether service credits can satisfy the penalty clause instead. Renewal risk: 79/100, but financial impact is confirmed regardless of renewal outcome.'),

('DOC-017', 'Support Case Note', 'CASE-88967: Pinnacle Biotech - Compliance Audit Concerns', 'West', 'Enterprise', 'Pinnacle Biotech',
 '2026-06-11',
 'Customer: Pinnacle Biotech. Case opened by Chief Compliance Officer. Issue: INC-0001 downtime occurred during an active FDA audit window. Customer was unable to produce required data exports for 3 audit queries during the incident. While the audit team granted a 48-hour extension, customer states this created reputational risk with their regulator. They are requesting: (1) formal incident documentation suitable for regulatory filing, (2) enhanced SLA with specific compliance-workload guarantees, (3) dedicated support contact for future audit windows. Customer indicated that platform reliability is now a board-level discussion topic for their upcoming renewal. Contract: $1.7M ARR, renewal 2026-09-15. Renewal risk: 81/100.'),

('DOC-018', 'Support Case Note', 'CASE-89001: Summit Analytics Group - Performance Degradation Report', 'West', 'Enterprise', 'Summit Analytics Group',
 '2026-06-12',
 'Customer: Summit Analytics Group. Case opened by VP Engineering. Issue: Customer reports 40% increase in average query latency for their top-20 most-executed queries comparing the week before INC-0001 to the week after. Engineering review confirms a 12% latency increase attributable to temporary storage rebalancing performed as part of INC-0001 remediation, expected to normalize within 2 weeks. Remaining 28% increase is due to customer workload growth (new data sources onboarded). Customer is conflating both issues with INC-0001 impact. Recommended: schedule technical deep-dive with customer engineering team to separate incident impact from organic growth. Contract: $2.1M ARR, renewal 2026-08-20. Renewal risk: 80/100.'),

('DOC-019', 'Support Case Note', 'CASE-89045: NovaPay Financial - Transaction Processing SLA Breach', 'West', 'Enterprise', 'NovaPay Financial',
 '2026-06-13',
 'Customer: NovaPay Financial. Case opened by COO. Issue: During INC-0001, their real-time transaction scoring pipeline was unavailable for 4 hours 23 minutes. Per their contract addendum, transaction processing workloads carry a 99.99% SLA (stricter than standard). Breach penalty: $50K per hour of downtime beyond 5 minutes = $215K credit owed. Customer states this is the first SLA breach in 3 years of partnership and while they remain committed to the platform, they require: (1) immediate credit issuance, (2) dedicated infrastructure isolation for their transaction workloads, (3) quarterly reliability review cadence. Contract: $3.6M ARR, renewal 2026-07-15. Renewal risk: 76/100 (lower than peers due to strong relationship, but financially impactful).'),

('DOC-020', 'Support Case Note', 'CASE-89112: Redwood Capital Management - Data Integrity Concerns', 'West', 'Enterprise', 'Redwood Capital Management',
 '2026-06-14',
 'Customer: Redwood Capital Management. Case opened by Head of Quantitative Research. Issue: Customer ran data integrity checks after INC-0001 and found 47 rows in a critical pricing table with NULL values where data should exist. Investigation shows these NULLs pre-date the incident (data quality issue in upstream feed), but customer initially attributed them to the outage. After joint investigation, customer acknowledged the NULLs are pre-existing, but expressed concern: "If we cannot trust the platform during an outage, how do we verify nothing was corrupted?" Requesting formal data integrity attestation for all tables modified during the incident window. Contract: $2.9M ARR, renewal 2026-09-01. Renewal risk: 74/100.'),

-- East region support cases for realism
('DOC-021', 'Support Case Note', 'CASE-89200: Atlantic Commerce Group - Warehouse Scaling Optimization', 'East', 'Enterprise', 'Atlantic Commerce Group',
 '2026-06-10',
 'Customer: Atlantic Commerce Group. Case opened by Data Platform Manager. Issue: Routine performance optimization request. Customer experiencing longer-than-expected queue times during their 9-11am peak window. Recommended multi-cluster warehouse configuration with min 2 / max 6 clusters. Customer approved change, implemented same day. No reliability concerns. Account health: GREEN. Renewal risk: 23/100. Contract: $1.8M ARR, renewal 2026-12-01.'),

('DOC-022', 'Support Case Note', 'CASE-89234: Northeastern Healthcare Alliance - Data Sharing Setup', 'East', 'Enterprise', 'Northeastern Healthcare Alliance',
 '2026-06-12',
 'Customer: Northeastern Healthcare Alliance. Case opened by Director of Interoperability. Issue: Customer requesting assistance setting up secure data sharing with 3 partner hospital systems. Standard implementation engagement, no platform concerns. Customer praised platform stability and ease of data sharing configuration. Account health: GREEN. Renewal risk: 18/100. Contract: $2.2M ARR, renewal 2026-11-15.'),

-- Central support case
('DOC-023', 'Support Case Note', 'CASE-89267: MidStates Energy Corp - Cost Optimization Review', 'Central', 'Enterprise', 'MidStates Energy Corp',
 '2026-06-11',
